@set projectName=bat
@cd ..
@svn update
@cd %projectName%

@svn info -r HEAD ../>youngest.txt
@if not exist youngest.txt goto END
@findstr . youngest.txt>nul&&(set FileSize=1)||(set FileSize=0)
@if %FileSize%==0 goto END

@echo /**														>drv_ver.c
@echo  *  @file drv_ver.c										>>drv_ver.c
@echo  *  @version v1.0											>>drv_ver.c
@echo  *  @author wangshiwei [<PRESIDIO_ANONYMIZED_EMAIL_ADDRESS>]			>>drv_ver.c
@echo  *  Copyright (c) 2004 BEIJING SIFANG AUTOMATION CO.,LTD.	>>drv_ver.c
@echo  */														>>drv_ver.c

@echo OFF
@for /f "delims=: tokens=1,2" %%i in (youngest.txt) do (
@set str1=%%i,
@if "%%i"=="Last Changed Rev" (
@echo const unsigned long g_drv_ver = %%j;								>>drv_ver.c
@del youngest.txt
@goto END
)

)

:END
@echo ON
@type drv_ver.c
